    42→class FilterChainUtility : Logger::Loggable<Logger::Id::config> {
    43→public:
    44→  struct FilterFactoryProvider {
    45→    Filter::FilterConfigProviderPtr<Filter::NamedHttpFilterFactoryCb> provider;
    46→    // If true, this filter is disabled by default and must be explicitly enabled by
    47→    // route configuration.
    48→    bool disabled{};
    49→  };
